(async () => {
	const wait = (ms) => new Promise((resolve) => setTimeout(resolve, ms));
	const assert = (condition, message) => {
		if (!condition) throw new Error(message);
	};
	const withTimeout = (promise, label, timeoutMs = 15000) =>
		Promise.race([

		promise,
			new Promise((_, reject) => window.setTimeout(() => reject(new Error(`${label} timed out`)), timeoutMs)),
		]);
	const waitFor = async (fn, { timeoutMs = 15000, stepMs = 50 } = {}) => {
		const started = Date.now();
		let last = null;
		while (Date.now() - started < timeoutMs) {
			last = await fn();
			if (last) return last;
			await wait(stepMs);
		}
		return last;
	};

	const pluginId = "block-link-plus";
	const tmpFolder = "_blp_tmp";
	const sourceAPath = `${tmpFolder}/blp2-switch-source-a.md`;
	const sourceBPath = `${tmpFolder}/blp2-switch-source-b.md`;
	const hostAPath = `${tmpFolder}/blp2-switch-host-a.md`;
	const hostBPath = `${tmpFolder}/blp2-switch-host-b.md`;
	const sourceAContent = [
		"# BLP2 source A",
		"",
		"- Alpha editable target ^blp2a",
		"  - Alpha child",
		"",
	].join("\n");
	const sourceBContent = [
		"# BLP2 source B",
		"",
		"- Beta editable target ^blp2b",
		"  - Beta child",
		"",
	].join("\n");
	const hostAContent = [`![[${sourceAPath}#^blp2a]]`, ""].join("\n");
	const hostBContent = [`![[${sourceBPath}#^blp2b]]`, ""].join("\n");
	const settingKeys = ["inlineEditEnabled", "inlineEditBlock", "inlineEditHeading", "inlineEditFile"];

	const upsert = async (filePath, content) => {
		let file = app.vault.getAbstractFileByPath(filePath);
		if (!file) file = await withTimeout(app.vault.create(filePath, content), `create ${filePath}`);
		else await withTimeout(app.vault.modify(file, content), `modify ${filePath}`);
		return file;
	};
	const snapshotSettings = (plugin) => {
		const settings = plugin?.settings ?? {};
		return Object.fromEntries(settingKeys.map((key) => [key, settings[key]]));
	};
	const restoreSettings = async (plugin, snapshot) => {
		if (!plugin || !snapshot) return;
		for (const key of settingKeys) plugin.settings[key] = snapshot[key];
		await plugin.saveSettings?.();
		plugin.inlineEditEngine?.onSettingsChanged?.();
	};
	const openInLeaf = async (leaf, filePath) => {
		const file = app.vault.getAbstractFileByPath(filePath);
		assert(file, `missing file ${filePath}`);
		await withTimeout(
			leaf.setViewState({ type: "markdown", state: { file: filePath, mode: "source" }, active: true }),
			`open ${filePath}`
		);
		app.workspace.setActiveLeaf?.(leaf, { focus: true });
		await waitFor(() => leaf.view?.file?.path === filePath && leaf.view?.containerEl?.querySelector(".markdown-source-view"));
		return leaf;
	};
	const getEmbed = (leaf) => leaf.view?.containerEl?.querySelector(".internal-embed.markdown-embed") ?? null;
	const describeLeaf = (label, leaf) => {
		const embed = getEmbed(leaf);
		const root = embed?.querySelector(".blp-inline-edit-root") ?? null;
		const host = embed?.querySelector(".blp-inline-edit-host") ?? null;
		const content = embed?.querySelector(".markdown-embed-content") ?? null;
		return {
			label,
			file: leaf.view?.file?.path ?? null,
			isShown: Boolean(leaf.view?.containerEl?.isShown?.()),
			embedConnected: Boolean(embed?.isConnected),
			embedClass: embed?.className ?? null,
			hasInlineActiveClass: Boolean(embed?.classList?.contains("blp-inline-edit-active")),
			hasRoot: Boolean(root),
			hasHost: Boolean(host),
			hasContent: Boolean(content),
			embedText: String(embed?.innerText ?? embed?.textContent ?? "").replace(/\s+/g, " ").trim(),
			activeEmbeds: app.plugins.plugins[pluginId]?.inlineEditEngine?.leaves?.getActiveEmbeds?.().length ?? null,
			observerCount: app.plugins.plugins[pluginId]?.inlineEditEngine?.livePreviewObservers?.size ?? null,
		};
	};

	const wasPluginEnabled = Boolean(app.plugins.plugins[pluginId]);
	let originalSettings = wasPluginEnabled ? snapshotSettings(app.plugins.plugins[pluginId]) : null;

	try {
		try {
			if (!app.vault.getAbstractFileByPath(tmpFolder)) await app.vault.createFolder(tmpFolder);
		} catch {
			// ignore existing folder races
		}
		await upsert(sourceAPath, sourceAContent);
		await upsert(sourceBPath, sourceBContent);
		await upsert(hostAPath, hostAContent);
		await upsert(hostBPath, hostBContent);

		if (app.plugins.plugins[pluginId]) {
			await withTimeout(app.plugins.disablePlugin(pluginId), "disable plugin for clean runtime");
			await wait(300);
		}
		await withTimeout(app.plugins.enablePlugin(pluginId), "enable plugin");
		await wait(500);
		const plugin = app.plugins.plugins[pluginId];
		assert(plugin, "Block Link Plus did not load");
		if (!originalSettings) originalSettings = snapshotSettings(plugin);
		plugin.settings.inlineEditEnabled = true;
		plugin.settings.inlineEditBlock = true;
		plugin.settings.inlineEditHeading = true;
		plugin.settings.inlineEditFile = false;
		await plugin.saveSettings?.();
		plugin.inlineEditEngine?.onSettingsChanged?.();

		const leafA = app.workspace.getLeaf(false);
		await openInLeaf(leafA, hostAPath);
		await waitFor(() => getEmbed(leafA)?.querySelector(".blp-inline-edit-root .cm-content, .blp-inline-edit-root.cm-content"));
		const beforeA = describeLeaf("A before switch", leafA);

		const leafB = app.workspace.getLeaf("tab");
		await openInLeaf(leafB, hostBPath);
		await waitFor(() => getEmbed(leafB)?.querySelector(".blp-inline-edit-root .cm-content, .blp-inline-edit-root.cm-content"));
		await wait(500);
		const afterBOpenA = describeLeaf("A hidden after B open", leafA);
		const afterBOpenB = describeLeaf("B active after B open", leafB);

		app.workspace.setActiveLeaf?.(leafA, { focus: true });
		await wait(1000);
		const afterReturnA = describeLeaf("A returned without reopen", leafA);

		const engine = plugin.inlineEditEngine;
		if (engine?.refreshLivePreviewObservers) {
			engine.refreshLivePreviewObservers(false);
			await wait(500);
		}
		const afterNonForcedRefreshA = describeLeaf("A after non-forced refresh", leafA);

		if (engine?.refreshLivePreviewObservers) {
			engine.refreshLivePreviewObservers(true);
			await waitFor(() => getEmbed(leafA)?.querySelector(".blp-inline-edit-root .cm-content, .blp-inline-edit-root.cm-content"), {
				timeoutMs: 10000,
			});
		}
		await wait(300);
		const afterForcedRescanA = describeLeaf("A after force rescan", leafA);

		return {
			ok: true,
			pluginVersion: plugin.manifest?.version ?? app.plugins.manifests?.[pluginId]?.version ?? null,
			runtime: {
				title: document.title,
				activeFile: app.workspace.getActiveFile?.()?.path ?? null,
				leafAId: leafA.id ?? null,
				leafBId: leafB.id ?? null,
			},
			states: [beforeA, afterBOpenA, afterBOpenB, afterReturnA, afterNonForcedRefreshA, afterForcedRescanA],
			forcedRescanRestored:
				afterNonForcedRefreshA.hasRoot === false &&
				afterNonForcedRefreshA.hasHost === false &&
				afterForcedRescanA.hasRoot === true &&
				afterForcedRescanA.hasHost === true,
			originalPluginEnabled: wasPluginEnabled,
			originalSettings,
		};
	} finally {
		try {
			let plugin = app.plugins.plugins[pluginId];
			if (!plugin && wasPluginEnabled) {
				await withTimeout(app.plugins.enablePlugin(pluginId), "restore plugin enabled state");
				await wait(300);
				plugin = app.plugins.plugins[pluginId];
			}
			await restoreSettings(plugin, originalSettings);
			if (!wasPluginEnabled && app.plugins.plugins[pluginId]) {
				await withTimeout(app.plugins.disablePlugin(pluginId), "restore plugin disabled state");
			}
		} catch {
			// keep the repro result instead of hiding it behind cleanup errors
